  useEffect(() => {
    if (!lastUpdated) return;
    const update = () =>
      setTimeAgo(formatDistanceToNow(lastUpdated, { addSuffix: true }));
    update();
    const id = setInterval(update, 10_000);
    return () => clearInterval(id);
