      )}

      {/* Error state */}
      {error && !rateLimited && (
        <Alert variant="destructive" className="border-red-500/30 bg-red-500/5">
          <AlertCircle className="h-4 w-4" />
          <AlertDescription className="text-xs">
            {error} Ã¢â‚¬â€ showing cached data if available.
          </AlertDescription>
        </Alert>
      )}

      {/* Loading skeleton */}
      {loading && (
        <>
          {/* Desktop side-by-side skeleton */}
          <div className="hidden sm:grid grid-cols-2 gap-3">
            <SkeletonTable rows={count} type="gainer" />
            <SkeletonTable rows={count} type="loser" />
          </div>
          {/* Mobile tabbed skeleton */}
          <div className="sm:hidden">
            <SkeletonTable rows={count} type="gainer" />
          </div>
        </>
      )}

      {/* Data tables */}
      {!loading && gainers.length > 0 && (
        <>
          {/* Desktop: side by side */}
          <div className="hidden sm:grid grid-cols-2 gap-3">
            <MoverTable coins={gainers} type="gainer" />
            <MoverTable coins={losers} type="loser" />
          </div>

          {/* Mobile: tabbed */}
          <div className="sm:hidden">
            <Tabs defaultValue="gainers">
              <TabsList className="w-full bg-zinc-800/60 mb-2">
                <TabsTrigger
                  value="gainers"
                  className="flex-1 text-xs data-[state=active]:bg-emerald-500/15 data-[state=active]:text-emerald-400"
                >
                  Gainers
                </TabsTrigger>
                <TabsTrigger
                  value="losers"
                  className="flex-1 text-xs data-[state=active]:bg-red-500/15 data-[state=active]:text-red-400"
                >
                  Losers
                </TabsTrigger>
              </TabsList>
              <TabsContent value="gainers">
                <MoverTable coins={gainers} type="gainer" />
              </TabsContent>
              <TabsContent value="losers">
                <MoverTable coins={losers} type="loser" />
              </TabsContent>
            </Tabs>
          </div>
        </>
      )}

      {/* Empty state */}
      {!loading && !error && gainers.length === 0 && (
