import { useState, useEffect, useCallback } from "react";

export interface CoinData {
  id: string;
  symbol: string;
  name: string;
  image: string;
  current_price: number;
  price_change_percentage_24h: number | null;
  market_cap_rank: number;
}

interface UseCryptoDataReturn {
  gainers: CoinData[];
  losers: CoinData[];
  loading: boolean;
  error: string | null;
  lastUpdated: Date | null;
  refresh: () => void;
}

const API_URL = "/api/proxy?url=" + encodeURIComponent(
  "https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&order=market_cap_desc&per_page=100&page=1&sparkline=false"
);

export function useCryptoData(count: number): UseCryptoDataReturn {
  const [allCoins, setAllCoins] = useState<CoinData[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const fetchData = useCallback(async (isInitial = false) => {
    if (isInitial) setLoading(true);
    setError(null);
    try {
      const res = await fetch(API_URL);
      if (!res.ok) throw new Error(`API error: ${res.status}`);
      const data: CoinData[] = await res.json();
      setAllCoins(data.filter((c) => c.price_change_percentage_24h !== null));
      setLastUpdated(new Date());
    } catch (err: any) {
      setError(err.message || "Failed to fetch data");
    } finally {
      if (isInitial) setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData(true);
    const interval = setInterval(() => fetchData(false), 90_000);
    return () => clearInterval(interval);
  }, [fetchData]);

  const sorted = [...allCoins].sort(
    (a, b) => (b.price_change_percentage_24h ?? 0) - (a.price_change_percentage_24h ?? 0)
  );

  const gainers = sorted.slice(0, count);
  const losers = sorted.slice(-count).reverse().sort(
    (a, b) => (a.price_change_percentage_24h ?? 0) - (b.price_change_percentage_24h ?? 0)
  );

  return { gainers, losers, loading, error, lastUpdated, refresh: () => fetchData(false) };
}

