import React from "react";
import { TrendingUp, TrendingDown } from "lucide-react";
import { CoinData } from "../hooks/useCryptoData";

interface MoverTableProps {
  coins: CoinData[];
  type: "gainer" | "loser";
}

function formatPrice(price: number): string {
  if (price >= 1) return price.toLocaleString("en-US", { style: "currency", currency: "USD", minimumFractionDigits: 2, maximumFractionDigits: 2 });
  if (price >= 0.01) return price.toLocaleString("en-US", { style: "currency", currency: "USD", minimumFractionDigits: 4, maximumFractionDigits: 4 });
  return price.toLocaleString("en-US", { style: "currency", currency: "USD", minimumFractionDigits: 6, maximumFractionDigits: 6 });
}

export function MoverTable({ coins, type }: MoverTableProps) {
  const isGainer = type === "gainer";
  const accentText = isGainer ? "text-emerald-400" : "text-red-400";
  const accentBg = isGainer ? "bg-emerald-500/10" : "bg-red-500/10";
  const borderColor = isGainer ? "border-emerald-500/20" : "border-red-500/20";
  const headerBg = isGainer ? "bg-emerald-500/5" : "bg-red-500/5";

  return (
    <div className={`border ${borderColor} overflow-hidden`}>
      {/* Header */}
      <div className={`${headerBg} px-3 py-2.5 flex items-center gap-2 border-b ${borderColor}`}>
        {isGainer ? (
          <TrendingUp className="w-4 h-4 text-emerald-400" />
        ) : (
          <TrendingDown className="w-4 h-4 text-red-400" />
        )}
        <span className={`text-xs font-bold uppercase tracking-wider ${accentText}`}>
          {isGainer ? "Top Gainers" : "Top Losers"}
        </span>
      </div>

      {/* Column headers */}
      <div className="grid grid-cols-[28px_1fr_auto_auto] gap-2 px-3 py-1.5 text-[11px] text-zinc-500 uppercase tracking-wider border-b border-zinc-800">
        <span>#</span>
        <span>Coin</span>
        <span className="text-right">Price</span>
        <span className="text-right w-[80px]">24h %</span>
      </div>

      {/* Rows */}
      <div>
        {coins.map((coin, idx) => {
          const pct = coin.price_change_percentage_24h ?? 0;
          return (
            <div
              key={coin.id}
              className={`grid grid-cols-[28px_1fr_auto_auto] gap-2 px-3 py-2 items-center border-b border-zinc-800/50 last:border-b-0 hover:bg-zinc-800/30 transition-colors`}
            >
              {/* Rank */}
              <span className="text-[11px] text-zinc-500 font-mono">{idx + 1}</span>

              {/* Coin info */}
              <div className="flex items-center gap-2 min-w-0">
                <img
                  src={coin.image}
                  alt={coin.name}
                  className="w-5 h-5 flex-shrink-0"
                  loading="lazy"
                />
                <div className="min-w-0">
                  <div className="text-xs text-zinc-100 font-medium truncate leading-tight">
                    {coin.name}
                  </div>
                  <div className="text-[10px] text-zinc-500 uppercase">{coin.symbol}</div>
                </div>
              </div>

              {/* Price */}
              <span className="text-xs text-zinc-300 font-mono text-right tabular-nums">
                {formatPrice(coin.current_price)}
              </span>

              {/* 24h % */}
              <div className={`flex items-center justify-end gap-1 w-[80px] ${accentBg} px-1.5 py-0.5`}>
                {isGainer ? (
                  <TrendingUp className={`w-3 h-3 ${accentText} flex-shrink-0`} />
                ) : (
                  <TrendingDown className={`w-3 h-3 ${accentText} flex-shrink-0`} />
                )}
                <span className={`text-xs font-mono font-bold tabular-nums ${accentText}`}>
                  {pct > 0 ? "+" : ""}
                  {pct.toFixed(2)}%
                </span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

